package framework.core.org.apache.manifoldcf.core.cachemanager;

protected class ExpirationTreeNode { protected ExpirationTreeNode lesser = null ; protected ExpirationTreeNode greater = null ; protected ObjectRecord firstSame = null ; protected ObjectRecord lastSame = null ; public ExpirationTreeNode ( ObjectRecord record ) { firstSame = record ; lastSame = record ; } public long getExpirationTime ( ) { return firstSame . getExpirationTime ( ) ; } public ExpirationTreeNode getLesser ( ) { return lesser ; } public void setLesser ( ExpirationTreeNode lesser ) { this . lesser = lesser ; } public ExpirationTreeNode getGreater ( ) { return greater ; } public void setGreater ( ExpirationTreeNode greater ) { this . greater = greater ; } public void addObjectRecord ( ObjectRecord x ) { x . setSameExpirationNext ( firstSame ) ; firstSame . setSameExpirationPrev ( x ) ; firstSame = x ; } public boolean removeObjectRecord ( ObjectRecord x ) { ObjectRecord prev = x . getSameExpirationPrev ( ) ; ObjectRecord next = x . getSameExpirationNext ( ) ; if ( prev == null ) firstSame = next ; else prev . setSameExpirationNext ( next ) ; if ( next == null ) lastSame = prev ; else next . setSameExpirationPrev ( prev ) ; x . setSameExpirationPrev ( null ) ; x . setSameExpirationNext ( null ) ; return ( firstSame == null ) ; } public ObjectRecord getOldest ( ) { return lastSame ; } }